mapper.select:
select notice_id, student_id, title, content, type, biz_type, biz_id, publish_time, read_flag, read_time, created_at, updated_at
from student_notice
where student_id = #{studentId}

    and read_flag = #{readFlag}

order by publish_time desc, notice_id desc

select notice_id, student_id, title, content, type, biz_type, biz_id, publish_time, read_flag, read_time, created_at, updated_at
from student_notice
where notice_id = #{noticeId}

select notice_id, student_id, title, content, type, biz_type, biz_id, publish_time, read_flag, read_time, created_at, updated_at
from student_notice
where notice_id = #{noticeId}
  and student_id = #{studentId}

mapper.update:
update student_notice
set read_flag = '1',
    read_time = #{readTime},
    updated_at = #{readTime}
where notice_id = #{noticeId}
  and student_id = #{studentId}
  and read_flag = '0'

update student_notice
set read_flag = '1',
    read_time = #{readTime},
    updated_at = #{readTime}
where student_id = #{studentId}
  and read_flag = '0'
